pointMarker.code:
type PointMarkerVariant = "default" | "muted" | "completed" | "emphasized";

interface PointMarkerProps {
  variant: PointMarkerVariant;
  label: string;
  selected?: boolean;
}

export function PointMarker({ variant, label, selected }: PointMarkerProps) {
  const interactive = variant === "default" || variant === "completed" || variant === "emphasized";
  return (
    <MapOverlayMarker
      className={`MapMarker--point-${variant} ${selected ? "is-selected" : ""}`}
      interactive={interactive}
      label={label}
    />
  );
}

informatedLocation.code:
type InformatedLocationVariant = "default" | "disabled" | "completed" | "emphasized";

async function renderInformatedLocation(map: google.maps.Map, position: google.maps.LatLngLiteral, variant: InformatedLocationVariant) {
  const { AdvancedMarkerElement } = await google.maps.importLibrary("marker");
  const visualVariant = variant === "disabled" ? "muted" : variant;
  const content = document.createElement("div");
  content.className = `MapMarker MapMarker--advanced MapMarker--informated-${visualVariant}`;

  return new AdvancedMarkerElement({
    content,
    map,
    position,
  });
}
